function AppInstall()
{
	x_snc_devtools.AppInstall();

	var installer = new x_snc_devtools.InstallerAPI(x_snc_devtools.GetAppName('x_snc_crisis'));

	installer.RecordInsertOrUpdate(
		'Add read access for Crisis Viewers on core_company',
		'sys_security_acl_role',
		{
			sys_scope: 'global',
			sys_security_acl: '8109a169c0a801666217a6825787c7ff',
			sys_user_role: 'd80cae87dbefc114bcced03cd39619b0'
		},
		{
			sys_user_role: 'd80cae87dbefc114bcced03cd39619b0'
		},
		{});

	installer.RecordInsertOrUpdate(
		'Add write access for Crisis Managers on core_company',
		'sys_security_acl_role',
		{
			sys_scope: 'global',
			sys_security_acl: '8bdc9b2f0a0a0b440190caa9004a8810',
			sys_user_role: 'a62cae87dbefc114bcced03cd39619ba'
		},
		{
			sys_user_role: 'a62cae87dbefc114bcced03cd39619ba'
		},
		{});	

	installer.RecordInsertOrUpdate(
		'Add create access for Crisis Managers on core_company',
		'sys_security_acl_role',
		{
			sys_scope: 'global',
			sys_security_acl: '1e28f9ff215a3010c0a0a40cdfd1e4a9',
			sys_user_role: 'a62cae87dbefc114bcced03cd39619ba'
		},
		{
			sys_user_role: 'a62cae87dbefc114bcced03cd39619ba'
		},
		{});	

	installer.RecordInsertOrUpdate(
		'Add write access for Crisis Managers on cmn_location',
		'sys_security_acl_role',
		{
			sys_scope: 'global',
			sys_security_acl: '8bdbc2b50a0a0b4400bb51800f135eb7',
			sys_user_role: 'a62cae87dbefc114bcced03cd39619ba'
		},
		{
			sys_user_role: 'a62cae87dbefc114bcced03cd39619ba'
		},
		{});		

	installer.RecordInsertOrUpdate(
		'Add create access for Crisis Managers on cmn_location',
		'sys_security_acl_role',
		{
			sys_scope: 'global',
			sys_security_acl: '8bdb877a0a0a0b44000816304694b511',
			sys_user_role: 'a62cae87dbefc114bcced03cd39619ba'
		},
		{
			sys_user_role: 'a62cae87dbefc114bcced03cd39619ba'
		},
		{});


	return installer.Finish();
}
